mapper.select:
SELECT COUNT(id)
FROM orders
WHERE order_time >= #{begin}
  AND order_time < #{end}

SELECT COUNT(id)
FROM orders
WHERE status = 5
  AND order_time >= #{begin}
  AND order_time < #{end}

SELECT COUNT(id)
FROM orders
WHERE status = 6
  AND order_time >= #{begin}
  AND order_time < #{end}

SELECT IFNULL(SUM(amount), 0)
FROM orders
WHERE status = 5
  AND order_time >= #{begin}
  AND order_time < #{end}

SELECT COUNT(id)
FROM `user`
WHERE create_time >= #{begin}
  AND create_time < #{end}
